module RefModule (
    input [7:0] a, // 8-bit fixed-point input a
    input [7:0] b, // 8-bit fixed-point input b
    output [7:0] sum // 8-bit fixed-point output sum
);
    wire [8:0] temp_sum; // 9-bit temp_sum to handle overflow

      wire _n01 = a[0] ^ b[0];
  wire _c01 = a[0] & b[0];
  wire _n02 = a[1] ^ b[1] ^ _c01;
  wire _c02 = (a[1] & b[1]) | (a[1] & _c01) | (b[1] & _c01);
  wire _n03 = a[2] ^ b[2] ^ _c02;
  wire _c03 = (a[2] & b[2]) | (a[2] & _c02) | (b[2] & _c02);
  wire _n04 = a[3] ^ b[3] ^ _c03;
  wire _c04 = (a[3] & b[3]) | (a[3] & _c03) | (b[3] & _c03);
  assign temp_sum = {_n01, _n02, _n03, _n04}; // Add inputs
    assign sum = temp_sum[7:0]; // Assign lower 8 bits (overflow is discarded)

endmodule
